  ('heelevel3-5ff21eeb-moex-00216', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'essay', '請具體說明「納稅者權利保護法」第 7 條對於納稅者濫用法律形式規
避稅捐時之實質課稅原則相關規定，並說明其相關罰則。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00217', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列何種稅捐之徵收，在我國法制中適用納稅者權利保護法，但不適用稅捐稽徵法？', '["房屋稅", "貨物稅", "關稅", "遺產稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00218', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '財政部得本於互惠原則，與外國政府或國際組織進行稅務用途資訊交換。但下列何種情形， 不得為之？', '["稅務用途資訊涉及納稅義務人之營業秘密者", "稅務用途資訊涉及之稅捐已經逾越核課期間者", "稅務用途資訊所涉案件，該管機關尚未依其能力盡力進行調查者", "稅務用途資訊涉及租稅獎勵措施者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00219', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅義務人以詐術或其他不正當方法逃漏稅捐者，構成稅捐稽徵法設有處罰明文之「詐術逃 漏稅捐」罪，學說上或稱「租稅詐欺」。關於租稅詐欺，下列描述何者正確？', '["租稅詐欺，不以相對人陷於錯誤為要素", "詐術逃漏稅捐罪，並非刑法339條普通詐欺罪之特別規定", "租稅詐欺僅限於逃漏國稅，地方稅不在處罰範圍內", "租稅詐欺之究辦，應當依行政程序法之規定為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00220', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '稅捐之徵收，原則上優先於無擔保之普通債權。但是下列何種稅捐，優先於一切債權及抵押權？', '["房屋稅", "契稅", "加值型營業稅", "個人綜合所得稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00221', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '根據我國稅捐稽徵法之規定，稅捐稽徵機關所得採取之稅捐保全措施，不包括下列何者？', '["限制欠稅納稅義務人出境", "限制欠稅納稅義務人從事奢侈消費", "由稅捐稽徵機關根據民法第244條規定，向法院提起撤銷訴權之訴訟", "由稅捐稽徵機關聲請法院就欠稅納稅義務人之財產實施假扣押"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00222', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '根據稅捐稽徵法之規定，因適用法令、認定事實、計算或其他原因之錯誤，致溢繳稅款者， 納稅義務人得於一定期間內，提出具體證明，申請退還，是為所謂「租稅核退請求權」或「退 稅請求權」。此一權利之行使，下列說明何者正確？', '["具有不當得利之屬性", "因可歸責於政府之事由而由納稅義務人提出請求者，其退稅請求權自繳納之日起二十年間 不行使而消滅", "納稅義務人對核定稅捐處分不服，依法提起行政救濟，經行政法院實體判決確定者，亦得 請求退稅", "溢繳之稅款，納稅義務人以現金繳納者，退稅之金額不必加計利息"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00223', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-111-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '財政部或經其指定之稅捐稽徵機關，對重大欠稅案件或重大逃漏稅捐案件經確定後，得公告 其欠稅人或逃漏稅捐人姓名或名稱與內容。此處所稱「確定」，不包括下列何種情形？', '["納稅義務人提起復查，機關作成復查決定後納稅義務人死亡而遺有繼承人者", "經訴願決定，納稅義務人未依法提起行政訴訟", "經行政訴訟終局裁判確定", "經稅捐稽徵機關核定之案件，納稅義務人未依法申請復查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:08+00:00", "source_pdf_sha1": "e14d959d6b66", "answer_pdf_sha1": "9ef231815386", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "323", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
